import numpy as np
import scipy


def compute_power_spectrum(x, fs, n_fft=2**12):
    """
    Compute the one-dimensional power spectrum of a signal using the discrete Fourier Transform (DFT).

    Parameters
    ----------
    x : np.ndarray
        Input 1D signal array.
    fs : float
        Sampling frequency of the signal in Hz.
    n_fft : int, optional
        Number of FFT points. Default is 2**12.

    Returns
    -------
    freq : np.ndarray
        Array of frequency bins (Hz), length n_fft//2 + 1.
    mag : np.ndarray
        Power spectrum (magnitude squared) for each frequency bin.

    Examples
    --------
    >>> x = np.random.randn(1024)
    >>> fs = 100.0
    >>> freq, mag = compute_power_spectrum(x, fs)
    >>> import matplotlib.pyplot as plt
    >>> plt.plot(freq, mag)
    >>> plt.xlabel("Frequency (Hz)")
    >>> plt.ylabel("Power")
    >>> plt.show()
    """
    x = x*np.hanning(len(x))
    yf = scipy.fftpack.fft(x, n=n_fft)
    N = int(len(yf)/2+1)

    mag = np.abs(yf[0:N])
    mag = mag*mag
    
    freq = np.linspace(0, fs/2, N)
    return freq, mag


def peakdet(v, delta, x=None):
    maxtab = []
    mintab = []
    
    v = np.asarray(v)

    if x is None:
        x = np.arange(len(v))
    
    mn, mx = np.Inf, -np.Inf
    mnpos, mxpos = np.NaN, np.NaN
    
    lookformax = True
    
    for i in np.arange(len(v)):
        this = v[i]
        if this > mx:
            mx = this
            mxpos = x[i]
        if this < mn:
            mn = this
            mnpos = x[i]
        
        if lookformax:
            if this < mx-delta:
                maxtab.append((mxpos, mx))
                mn = this
                mnpos = x[i]
                lookformax = False
        else:
            if this > mn+delta:
                mintab.append((mnpos, mn))
                mx = this
                mxpos = x[i]
                lookformax = True
    return np.array(maxtab), np.array(mintab)




def compute_correlation(signal1, signal2):
    # Ensure both signals are the same length
    min_len = min(len(signal1), len(signal2))
    signal1 = signal1 - np.mean(signal1)
    signal2 = signal2 - np.mean(signal2)
    corr = np.corrcoef(signal1[:min_len], signal2[:min_len])[0, 1]
    return corr